// ========================================
// 🧠 FORMATADOR DE ESTADO - EMMA (FOCO NO FLUXO)
// ========================================

// 1. INPUT
const inputData = $input.first().json; 
const leadPhone = inputData.initial_context?.phone_number || "Desconhecido";
const events = inputData.logs?.realtime_feedback_events || [];

let resumoChamada = "";
let conversation = [];

// ========================================
// 2. PROCESSAMENTO DA CONVERSA
// ========================================
events.forEach(event => {
  // BOT
  if (event.type === 'rtf-bot-text') {
    const text = event.payload?.text?.trim();
    if (text) {
      resumoChamada += `Emma: ${text}\n\n`;
      conversation.push({ role: "assistant", content: text });
    }
  }

  // USER
  if (event.type === 'rtf-user-transcription' && event.payload?.final === true) {
    const text = event.payload?.text?.trim();
    if (text) {
      const leadName = inputData.initial_context?.nome || inputData.initial_context?.lead_name || 'Cliente';
    resumoChamada += `${leadName}: ${text}\n\n`;
      conversation.push({ role: "user", content: text });
    }
  }
});

// Identificação da última fase pelo nó visitado
const lastNode = inputData.gathered_context?.nodes_visited?.slice(-1)[0] || "Finalização";

// ========================================
// 3. PAYLOAD (LIMPO E DIRETO)
// ========================================
const redisMessage = {
  type: "system",
  data: {
    content: `TRANSIÇÃO DE CHAMADA: O cliente ${leadName} acabou de falar com a Emma.

HISTÓRICO COMPLETO DA CONVERSA:
---------------------------------------
${resumoChamada}
---------------------------------------

FASE DA PARADA: ${lastNode}
WHATSAPP DO CLIENTE: ${leadPhone}

INSTRUÇÃO PARA O AGENTE: Leia o histórico acima para identificar os dados que o ${leadName} já informou (CPF, E-mail, Nascimento) e prossiga com o fechamento no WhatsApp sem repetir perguntas desnecessárias.`,

    conversation: conversation
  },
  metadata: {
    lead_phone: leadPhone,
    last_node: lastNode,
    timestamp: new Date().toISOString()
  }
};

// ========================================
// 4. OUTPUT
// ========================================
return [{
  json: {
    key: leadPhone,
    redis_payload: JSON.stringify(redisMessage)
  }
}];

parameters.text:
=Continue o atendimento no WhatsApp de forma natural e fluida.

DADOS DO LEAD:
- Nome: {{ $('dados').item.json.lead_name }}
- Telefone: {{ $('dados').item.json.lead_phone }}
- Motivo: {{ $('dados').item.json.handoff_reason }}

CONTEXTO:
{{ 
(() => {
  try {
    return JSON.parse($('Formatar Estado').item.json.redis_payload).data.content;
  } catch(e) {
    return "Sem contexto disponível";
  }
})()
}}

CONVERSA:
{{ 
(() => {
  try {
    const data = JSON.parse($('Formatar Estado').item.json.redis_payload);
    return JSON.stringify(data.data.conversation || []);
  } catch(e) {
    return "[]";
  }
})()
}}

PRODUTOS DISPONÍVEIS:
- INSS: Essencial (R$59,90), Plus (R$69,90), Premium (R$79,90)
- PF: Essencial (R$59,90), Plus (R$69,90), Premium (R$79,90)
- Code para proposta: BENMAIS_CLUB_ESSENCIAL/PLUS/PREMIUM, BENMAIS_PF_ESSENCIAL/PLUS/PREMIUM

ORIENTAÇÃO:

- Continue exatamente de onde a conversa parou

- Nunca repita perguntas já respondidas pelo cliente

- Considere toda a conversa, não apenas a última mensagem

- Se o cliente já forneceu informações, utilize-as

- Se algum dado estiver incompleto ou confuso, confirme de forma natural

- Seja fluido, humano e direto, como um atendimento real no WhatsApp

